import{_ as a,o as i,c as e,ag as d}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Chmod | Dotfiles (ID)","titleTemplate":":title","description":"Alias chmod untuk menyederhanakan manajemen izin file dan direktori. Pintasan cepat untuk pola izin umum seperti 755, 644, dan lainnya.","frontmatter":{"title":"Alias Chmod | Dotfiles","description":"Alias chmod untuk menyederhanakan manajemen izin file dan direktori. Pintasan cepat untuk pola izin umum seperti 755, 644, dan lainnya.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Chmod preview","canonical":"/id/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Chmod","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Chmod - Dotfiles (ID)","permalink":"/id/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliases, file permissions, shell shortcuts, dotfiles, unix permissions"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Chmod - Dotfiles"},{"name":"twitter:description","content":"Alias chmod untuk menyederhanakan manajemen izin file dan direktori."},{"name":"og:title","content":"Alias Chmod - Dotfiles"},{"name":"og:description","content":"Alias chmod untuk menyederhanakan manajemen izin file dan direktori."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/chmod/index.md","filePath":"id/aliases/chmod/index.md","lastUpdated":1773010926000}'),n={name:"id/aliases/chmod/index.md"};function o(r,t,s,c,l,h){return i(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="alias-chmod" tabindex="-1">Alias Chmod <a class="header-anchor" href="#alias-chmod" aria-label="Permalink to &quot;Alias Chmod&quot;">​</a></h1><p>Pintasan untuk manajemen izin file dan direktori.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias chmod menyediakan cara efisien untuk mengelola izin file dan direktori dari command line. Alih-alih mengingat kode izin numerik, gunakan alias intuitif seperti <code>chmod_755</code> atau <code>chmod_u+x</code> untuk mengatur mode akses yang diperlukan dengan cepat.</p><p>Alias ini didefinisikan di <code>chmod.aliases.sh</code> dan dimuat secara otomatis oleh chezmoi.</p><h2 id="referensi" tabindex="-1">Referensi <a class="header-anchor" href="#referensi" aria-label="Permalink to &quot;Referensi&quot;">​</a></h2><h3 id="alias-izin-umum" tabindex="-1">Alias Izin Umum <a class="header-anchor" href="#alias-izin-umum" aria-label="Permalink to &quot;Alias Izin Umum&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Izin</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Tidak ada izin untuk siapapun</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Hanya baca untuk pemilik saja</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Hanya baca untuk semua</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Baca tulis untuk pemilik saja</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Pemilik baca tulis, lainnya hanya baca</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Baca tulis untuk semua</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Penuh untuk pemilik, baca/eksekusi untuk lainnya</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Penuh untuk pemilik, baca tulis untuk grup</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Izin penuh untuk semua</td></tr></tbody></table><h3 id="alias-izin-pemilik" tabindex="-1">Alias Izin Pemilik <a class="header-anchor" href="#alias-izin-pemilik" aria-label="Permalink to &quot;Alias Izin Pemilik&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Tambah izin eksekusi untuk pemilik</td></tr><tr><td><code>chmod_u-x</code></td><td>Hapus izin eksekusi dari pemilik</td></tr><tr><td><code>chmod_u+w</code></td><td>Tambah izin tulis untuk pemilik</td></tr><tr><td><code>chmod_u-w</code></td><td>Hapus izin tulis dari pemilik</td></tr><tr><td><code>chmod_u+r</code></td><td>Tambah izin baca untuk pemilik</td></tr><tr><td><code>chmod_u-r</code></td><td>Hapus izin baca dari pemilik</td></tr></tbody></table><h3 id="alias-izin-grup" tabindex="-1">Alias Izin Grup <a class="header-anchor" href="#alias-izin-grup" aria-label="Permalink to &quot;Alias Izin Grup&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Tambah izin eksekusi untuk grup</td></tr><tr><td><code>chmod_g-x</code></td><td>Hapus izin eksekusi dari grup</td></tr><tr><td><code>chmod_g+w</code></td><td>Tambah izin tulis untuk grup</td></tr><tr><td><code>chmod_g-w</code></td><td>Hapus izin tulis dari grup</td></tr><tr><td><code>chmod_g+r</code></td><td>Tambah izin baca untuk grup</td></tr><tr><td><code>chmod_g-r</code></td><td>Hapus izin baca dari grup</td></tr></tbody></table><h3 id="alias-izin-lainnya" tabindex="-1">Alias Izin Lainnya <a class="header-anchor" href="#alias-izin-lainnya" aria-label="Permalink to &quot;Alias Izin Lainnya&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Tambah izin eksekusi untuk lainnya</td></tr><tr><td><code>chmod_o-x</code></td><td>Hapus izin eksekusi dari lainnya</td></tr><tr><td><code>chmod_o+w</code></td><td>Tambah izin tulis untuk lainnya</td></tr><tr><td><code>chmod_o-w</code></td><td>Hapus izin tulis dari lainnya</td></tr><tr><td><code>chmod_o+r</code></td><td>Tambah izin baca untuk lainnya</td></tr><tr><td><code>chmod_o-r</code></td><td>Hapus izin baca dari lainnya</td></tr></tbody></table><h3 id="alias-tipe-file" tabindex="-1">Alias Tipe File <a class="header-anchor" href="#alias-tipe-file" aria-label="Permalink to &quot;Alias Tipe File&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Atur izin semua direktori ke <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>Atur izin semua file ke <code>rw-r--r--</code></td></tr></tbody></table><h3 id="fungsi-izin-rekursif" tabindex="-1">Fungsi Izin Rekursif <a class="header-anchor" href="#fungsi-izin-rekursif" aria-label="Permalink to &quot;Fungsi Izin Rekursif&quot;">​</a></h3><p>Fungsi <code>change_permission</code> menerapkan izin secara rekursif dengan konfirmasi:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const k=a(n,[["render",o]]);export{m as __pageData,k as default};
